function toAmountBidSide(activeId, totalAmount, distributions, mintY, clock) {
  totalAmount = calculateTransferFeeExcludedAmount(
    totalAmount,
    mintY,
    clock.epoch.toNumber()
  ).amount;
  const totalWeight = distributions.reduce(function(sum, el) {
    return el.binId > activeId ? sum : sum.add(el.weight);
  }, new Decimal3(0));
  if (totalWeight.cmp(new Decimal3(0)) != 1) {
    throw Error("Invalid parameteres");
  }
  return distributions.map((bin) => {
    if (bin.binId > activeId) {
      return {
        binId: bin.binId,
        amount: new BN5(0)
      };
    } else {
      return {
        binId: bin.binId,
        amount: new BN5(
          new Decimal3(totalAmount.toString()).mul(new Decimal3(bin.weight).div(totalWeight)).floor().toString()
        )
      };
    }
  });
}
function toAmountAskSide(activeId, binStep, totalAmount, distributions, mintX, clock) {
  totalAmount = calculateTransferFeeExcludedAmount(
    totalAmount,
    mintX,
    clock.epoch.toNumber()
  ).amount;
  const totalWeight = distributions.reduce(function(sum, el) {
    if (el.binId < activeId) {
      return sum;
    } else {
      const price = getPriceOfBinByBinId(el.binId, binStep);
      const weightPerPrice = new Decimal3(el.weight).div(price);
      return sum.add(weightPerPrice);
    }
  }, new Decimal3(0));
  if (totalWeight.cmp(new Decimal3(0)) != 1) {
    throw Error("Invalid parameteres");
  }
  return distributions.map((bin) => {
    if (bin.binId < activeId) {
      return {
        binId: bin.binId,
        amount: new BN5(0)
      };
    } else {
      const price = getPriceOfBinByBinId(bin.binId, binStep);
      const weightPerPrice = new Decimal3(bin.weight).div(price);
      return {
        binId: bin.binId,
        amount: new BN5(
          new Decimal3(totalAmount.toString()).mul(weightPerPrice).div(totalWeight).floor().toString()
        )
      };
    }
  });
}
